// Define the environment variables expected by the Worker
interface Env {
  SENDGRID_API_KEY: string;
  STRIPE_SECRET_KEY: string;
}

// Helper function for creating JSON responses
function jsonResponse(data: any, status: number = 200, headers: HeadersInit = {}): Response {
  return new Response(JSON.stringify(data), {
    status: status,
    headers: { 'Content-Type': 'application/json', ...headers },
  });
}

// Helper function for creating error responses
function errorResponse(message: string, status: number = 500, details?: any): Response {
  const errorPayload: any = { error: message };
  if (details) {
    errorPayload.details = details;
  }
  return jsonResponse(errorPayload, status);
}

// Function to handle SendGrid email requests
async function handleEmail(request: Request, env: Env): Promise<Response> {
  // 1. API Authentication Check
  if (!env.SENDGRID_API_KEY) {
    return errorResponse('SendGrid API key is not configured.', 500);
  }

  // Ensure it's a POST request
  if (request.method !== 'POST') {
    return errorResponse('Method Not Allowed', 405);
  }

  // 2. Parse Request Body and Validate Input
  let emailData: { to: string; from: string; subject: string; text?: string; html?: string };
  try {
    emailData = await request.json();
    if (!emailData.to || !emailData.from || !emailData.subject || (!emailData.text && !emailData.html)) {
      return errorResponse('Missing required email fields (to, from, subject, text/html)', 400);
    }
  } catch (err: any) {
    return errorResponse('Invalid JSON payload for email.', 400, err.message);
  }

  const sendgridApiUrl = 'https://api.sendgrid.com/v3/mail/send';
  const emailPayload = {
    personalizations: [{ to: [{ email: emailData.to }] }],
    from: { email: emailData.from },
    subject: emailData.subject,
    content: [],
  };

  if (emailData.text) {
    emailPayload.content.push({ type: 'text/plain', value: emailData.text });
  }
  if (emailData.html) {
    emailPayload.content.push({ type: 'text/html', value: emailData.html });
  }

  // 3. Make Third-Party API Call and Handle Response
  try {
    const sgResponse = await fetch(sendgridApiUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      },
      body: JSON.stringify(emailPayload),
    });

    // SendGrid returns 202 Accepted for success, other codes indicate errors
    if (!sgResponse.ok) {
      const errorBody = await sgResponse.text();
      // Error handling for SendGrid specific issues
      return errorResponse(`SendGrid API error: ${sgResponse.status} ${sgResponse.statusText}`, sgResponse.status, errorBody);
    }

    // Success response: SendGrid often returns 202 with an empty body
    return jsonResponse({ message: 'Email sent successfully' }, 200);

  } catch (err: any) {
    // 4. Handle Network/Unexpected Errors
    return errorResponse('Failed to send email due to network or SendGrid API issues.', 500, err.message);
  }
}

// Function to handle Stripe payment requests
async function handlePayment(request: Request, env: Env): Promise<Response> {
  // 1. API Authentication Check
  if (!env.STRIPE_SECRET_KEY) {
    return errorResponse('Stripe secret key is not configured.', 500);
  }

  // Ensure it's a POST request
  if (request.method !== 'POST') {
    return errorResponse('Method Not Allowed', 405);
  }

  // 2. Parse Request Body and Validate Input
  let paymentData: { amount: number; currency: string; description?: string; paymentMethodId?: string; customerId?: string };
  try {
    paymentData = await request.json();
    if (!paymentData.amount || !paymentData.currency) {
      return errorResponse('Missing required payment fields (amount, currency)', 400);
    }
    if (typeof paymentData.amount !== 'number' || paymentData.amount <= 0) {
      return errorResponse('Amount must be a positive number', 400);
    }
    // Stripe expects amount in the smallest currency unit (e.g., cents for USD).
    // Assuming 'amount' received is already in cents. If it's in dollars, multiply by 100.
    // E.g., const amountInCents = Math.round(paymentData.amount * 100);
  } catch (err: any) {
    return errorResponse('Invalid JSON payload for payment.', 400, err.message);
  }

  const stripeApiUrl = 'https://api.stripe.com/v1/payment_intents';
  const stripePayload: any = {
    amount: paymentData.amount, // Expecting amount in smallest currency unit (e.g., cents)
    currency: paymentData.currency,
    description: paymentData.description || 'Payment via Cloudflare Worker',
    automatic_payment_methods: { enabled: true }, // Enables client-side setup for many payment methods
  };

  // If a payment method is provided, attempt to confirm the PaymentIntent immediately
  if (paymentData.paymentMethodId) {
    stripePayload.payment_method = paymentData.paymentMethodId;
    stripePayload.confirm = true;
    if (paymentData.customerId) {
      stripePayload.customer = paymentData.customerId;
    }
  } else if (paymentData.customerId) {
    // If no paymentMethodId but customerId, create a PaymentIntent linked to the customer
    stripePayload.customer = paymentData.customerId;
  }
  // If neither paymentMethodId nor customerId is provided, the PaymentIntent is created
  // for client-side confirmation using Stripe.js

  // 3. Make Third-Party API Call and Handle Response
  try {
    const stripeResponse = await fetch(stripeApiUrl, {
      method: 'POST',
      headers: {
        // Stripe API often expects `application/x-www-form-urlencoded` for POST requests
        'Content-Type': 'application/x-www-form-urlencoded',
        Authorization: `Bearer ${env.STRIPE_SECRET_KEY}`,
      },
      // Convert the payload to URL-encoded string
      body: new URLSearchParams(stripePayload).toString(),
    });

    const stripeJson = await stripeResponse.json();

    if (!stripeResponse.ok) {
      // Stripe errors have a specific format, often nested under 'error'
      return errorResponse(`Stripe API error: ${stripeResponse.status} ${stripeResponse.statusText}`, stripeResponse.status, stripeJson.error);
    }

    // Success response: Return the Stripe PaymentIntent object
    return jsonResponse(stripeJson);

  } catch (err: any) {
    // 4. Handle Network/Unexpected Errors
    return errorResponse('Failed to process payment due to network or Stripe API issues.', 500, err.message);
  }
}

// Main event listener for the Cloudflare Worker
export default {
  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
    const url = new URL(request.url);

    // Define CORS headers for security and browser compatibility
    // In production, tighten 'Access-Control-Allow-Origin' to your frontend domain(s)
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET,HEAD,POST,OPTIONS',
      'Access-Control-Max-Age': '86400', // Cache preflight requests for 24 hours
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    // Handle OPTIONS requests (CORS preflight)
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    let response: Response;

    try {
      // Route requests based on the URL path
      if (url.pathname === '/email') {
        response = await handleEmail(request, env);
      } else if (url.pathname === '/payment') {
        response = await handlePayment(request, env);
      } else {
        // Handle unknown routes
        response = errorResponse('Not Found', 404);
      }
    } catch (err: any) {
      // Catch any unexpected errors that might occur during routing or handler execution
      response = errorResponse('An unexpected internal server error occurred.', 500, err.message);
    }

    // Apply CORS headers to all responses
    for (const [key, value] of Object.entries(corsHeaders)) {
      response.headers.set(key, value);
    }

    return response;
  },
};